import type { App, Component, Plugin } from 'vue'
import { AviatorExpressionBuilder, AviatorExpressionBuilderModal } from './components'
import { AviatorExpressionBuilderLegacyModal } from './legacy'

export interface AviatorExpressionBuilderPluginComponentNames {
  builder?: string
  modal?: string
  legacyModal?: string
}

export interface AviatorExpressionBuilderPluginOptions {
  prefix?: string
  includeLegacy?: boolean
  componentNames?: AviatorExpressionBuilderPluginComponentNames
}

type ComponentRegistrationKey = 'builder' | 'modal' | 'legacyModal'

interface ComponentRegistration {
  key: ComponentRegistrationKey
  defaultName: string
  component: Component
}

const CORE_COMPONENTS: ReadonlyArray<ComponentRegistration> = [
  { key: 'builder', defaultName: 'AviatorExpressionBuilder', component: AviatorExpressionBuilder },
  { key: 'modal', defaultName: 'AviatorExpressionBuilderModal', component: AviatorExpressionBuilderModal },
]

const LEGACY_COMPONENT: ComponentRegistration = {
  key: 'legacyModal',
  defaultName: 'AviatorExpressionBuilderLegacyModal',
  component: AviatorExpressionBuilderLegacyModal,
}

function resolveComponentName(baseName: string, prefix?: string): string {
  return prefix ? `${prefix}${baseName}` : baseName
}

function resolveRegistrationName(
  registration: ComponentRegistration,
  options: AviatorExpressionBuilderPluginOptions,
): string {
  const explicitName = options.componentNames?.[registration.key]
  return resolveComponentName(explicitName || registration.defaultName, options.prefix)
}

function registerComponent(
  app: App,
  registration: ComponentRegistration,
  options: AviatorExpressionBuilderPluginOptions,
): void {
  const componentName = resolveRegistrationName(registration, options)
  if (!app.component(componentName)) {
    app.component(componentName, registration.component)
  }
}

export function installAviatorExpressionBuilder(
  app: App,
  options: AviatorExpressionBuilderPluginOptions = {},
): void {
  const { includeLegacy = false } = options

  CORE_COMPONENTS.forEach((registration) => {
    registerComponent(app, registration, options)
  })

  if (includeLegacy) {
    registerComponent(app, LEGACY_COMPONENT, options)
  }
}

export const AviatorExpressionBuilderPlugin: Plugin = {
  install(app: App, options?: AviatorExpressionBuilderPluginOptions) {
    installAviatorExpressionBuilder(app, options)
  },
}

export default AviatorExpressionBuilderPlugin
